    var csrf = document.querySelector('meta[name="csrf-token"]').content;
    var csrf_field = '<input type="hidden" name="_token" value="'+csrf+'">';
    var encodedParams =  $.base64.encode(formId);
    var key = $('meta[name="cookie"]').attr('content').split('.')[2];
