function getAge(dob)
{
    //var yearsDiff = moment().diff(dob, 'years');
    var Diff = moment().diff(dob);
    var Dur = moment.duration(Diff);
    var yearsDiff = Dur._data.years;

    if((Dur._data.months > 0) || (Dur._data.days > 0)){
          yearsDiff += 0.1;
    }

    return yearsDiff;

}

